// Pseudo-scaffold: bounded per-app queue with workers
class Partition {
  constructor(id) { this.id=id; this.q=[]; this.workers=2; }
  enqueue(ev){ if(this.q.length>MAX) throw 'backpressure'; this.q.push(ev); }
  async run(){
    while(this.q.length){ const e=this.q.shift(); await this.process(e); }
  }
  async process(e){ /* write to sink atomically; ensure idempotence */ }
}
```

