  }
  enqueue(task) {
    // block if globalQ full
    this.globalQ.enqueue(task);
  }
  workerLoop() {
    while (true) {
      for (const t of this.tenants.values()) {
        if (t.semaphore.tryAcquire()) {
          const x = t.queues[type].dequeue();
          if (x) process(x);
        }
      }
      // optional backoff
    }
  }
  updateCap(tenantId, newCap) {
    const t = this.tenants.get(tenantId);
    t.semaphore.updateLimit(newCap);
  }
}
