## Code Example
```go
// sketch in Go-like pseudocode
type inflight struct {
  done chan struct{}
  val  any
  err  error
  ref  int
}

var m = sync.Map{} // key -> *inflight

func get(key string, fetch func() (any, error)) (any, error) {
  if v, ok := m.Load(key); ok {
    inf := v.(*inflight)
    select {
    case <-inf.done:
      return inf.val, inf.err
    default:
      // wait for completion
      <-inf.done
      return inf.val, inf.err
    }
  }
  inf := &inflight{done: make(chan struct{})}
  actual, loaded := m.LoadOrStore(key, inf)
  if loaded {
    // another fetch started; wait
    return get(key, fetch)
  }
  // this goroutine performs fetch
  inf.ref++
  val, err := fetch()
  inf.val, inf.err = val, err
  close(inf.done)
  m.Delete(key)
  return val, err
}
```

