// Minimal bounded-priority sketch (illustrative)
class PriorityQueue {
  constructor(max){ this.max=max; this.q={high:[],med:[],low:[]}; this.size=0; }
  async enqueue(stream, item){
    while(this.size>=this.max) await new Promise(r=>setTimeout(r,1));
    this.q[stream.priority].push({stream,item});
    this.size++;
