## Code Example
```javascript
// Minimal EDF scheduler (Node.js)
class Task {
  constructor(id, deadline, payload){ this.id=id; this.deadline=deadline; this.payload=payload; this.cancelled=false; }
}
class EDFScheduler {
  constructor(concurrency=2){ this.queue=[]; this.concurrency=concurrency; this.active=0; this.running=true; }
  enqueue(t){ this.queue.push(t); this.queue.sort((a,b)=>a.deadline-b.deadline); }
  async nextTask(){ while(this.running){ if(this.queue.length){ const t=this.queue.shift(); if(!t.cancelled) return t; continue; } await new Promise(r=>setTimeout(r,1)); } return null; }
  async startWorker(){ if(this.active>=this.concurrency) return; this.active++; (async ()=>{ while(this.running){ const t=await this.nextTask(); if(!t) break; await new Promise(r=>setTimeout(r,10)); console.log(`done ${t.id}`); } this.active--; })(); }
  shutdown(){ this.running=false; }
}
(async ()=>{ const s=new EDFScheduler(2); const now=Date.now(); s.enqueue(new Task(1, now+200, {})); s.enqueue(new Task(2, now+100, {})); s.enqueue(new Task(3, now+150, {})); s.startWorker(); s.startWorker(); setTimeout(()=>s.shutdown(),500);})();
```

