## Why This Is Asked

This question evaluates practical concurrency control skills involving multiple producers, bounded buffers, and latency guarantees with a simple priority policy. The solution tests real-world challenges like starvation prevention and graceful shutdown coordination.

## Key Concepts

- Dual-queue architecture for priority separation
- Mutual exclusion and condition synchronization
- Backpressure mechanisms for flow control
- Aging algorithms to prevent starvation
- Graceful shutdown patterns with resource cleanup

## Code Example

```javascript
// Pseudo sketch of data structures and worker loop
class Task { 
  constructor(priority) { 
    this.priority = priority; 
    this.timestamp = Date.now();
  } 
}

class PriorityQueue {
  constructor(capacity) {
    this.capacity = capacity;
    this.highQueue = [];
    this.normalQueue = [];
    this.mutex = new Mutex();
    this.notEmpty = new ConditionVariable();
    this.notFull = new ConditionVariable();
    this.shutdown = false;
    this.agingThreshold = 5000; // 5 seconds
  }

  async enqueue(task) {
    await this.mutex.lock();
    while (this.size() >= this.capacity && !this.shutdown) {
      await this.notFull.wait();
    }

    if (task.priority === 'high') {
      this.highQueue.push(task);
    } else {
      this.normalQueue.push(task);
    }

    this.notEmpty.signal();
    this.mutex.unlock();
  }

  async dequeue() {
    await this.mutex.lock();
    while (this.size() === 0 && !this.shutdown) {
      await this.notEmpty.wait();
    }

    if (this.shutdown && this.size() === 0) {
      this.mutex.unlock();
      return null;
    }

    this.checkAging();

    let task;
    if (this.highQueue.length > 0) {
      task = this.highQueue.shift();
    } else if (this.normalQueue.length > 0) {
      task = this.normalQueue.shift();
    }

    this.notFull.signal();
    this.mutex.unlock();
    return task;
  }

  checkAging() {
    const now = Date.now();
    this.normalQueue = this.normalQueue.filter(task => {
      if (now - task.timestamp > this.agingThreshold) {
        this.highQueue.push(task);
        return false;
      }
      return true;
    });
  }

  size() {
    return this.highQueue.length + this.normalQueue.length;
  }

  async shutdown() {
    await this.mutex.lock();
    this.shutdown = true;
    this.notEmpty.broadcast();
    this.notFull.broadcast();
    this.mutex.unlock();
  }
}
```

