## Why This Question Is Asked
This tests understanding of per-topic ordering, backpressure mechanisms, dynamic topic management, and safe shutdown in a concurrent dispatcher system.

## Key Concepts
- **Bounded backlog and backpressure**: Prevent memory exhaustion by limiting queue depth and signaling producers when buffers are full
- **Per-topic FIFO with ordering guarantees**: Ensure events within each topic maintain publication order
- **Fair scheduling (round-robin)**: Prevent a high-volume topic from starving others
- **Dynamic topic management**: Support on-the-fly topic creation as new device types appear
- **Cancellation and graceful shutdown**: Safely drain pending work without data loss

## Code Example
```go
package main

import (
	"context"
	"fmt"
	"sync"
	"time"
)

type Event struct {
	Topic   string
	Payload string
}

type TopicQueue struct {
	ch     chan Event
	mu     sync.Mutex
	closed bool
}

type Dispatcher struct {
	globalBacklog chan Event
	topicQueues  map[string]*TopicQueue
	workers      int
	wg           sync.WaitGroup
	mu           sync.RWMutex
	ctx          context.Context
	cancel       context.CancelFunc
}

func NewDispatcher(backlogSize, workers int) *Dispatcher {
	ctx, cancel := context.WithCancel(context.Background())
	d := &Dispatcher{
		globalBacklog: make(chan Event, backlogSize),
		topicQueues:  make(map[string]*TopicQueue),
		workers:      workers,
		ctx:          ctx,
		cancel:       cancel,
	}
	return d
}

func (d *Dispatcher) getOrCreateTopic(topic string) *TopicQueue {
	d.mu.Lock()
	defer d.mu.Unlock()
	if q, ok := d.topicQueues[topic]; ok {
		return q
	}
	q := &TopicQueue{ch: make(chan Event, 100)}
	d.topicQueues[topic] = q
	return q
}

func (d *Dispatcher) Enqueue(e Event) error {
	select {
	case d.globalBacklog <- e:
		return nil
	default:
		return fmt.Errorf("backpressure: global backlog full")
	}
}

func (d *Dispatcher) Start() {
	for i := 0; i < d.workers; i++ {
		d.wg.Add(1)
		go d.worker(i)
	}
	go d.dispatcher()
}

func (d *Dispatcher) dispatcher() {
	for {
		select {
		case <-d.ctx.Done():
			return
		case e := <-d.globalBacklog:
			q := d.getOrCreateTopic(e.Topic)
			select {
			case q.ch <- e:
			default:
				fmt.Printf("backpressure: topic %s full\n", e.Topic)
			}
		}
	}
}

func (d *Dispatcher) worker(id int) {
	defer d.wg.Done()
	for {
		select {
		case <-d.ctx.Done():
			return
		default:
		}
		d.mu.RLock()
		topics := make([]string, 0, len(d.topicQueues))
		for t := range d.topicQueues {
			topics = append(topics, t)
		}
		d.mu.RUnlock()
		if len(topics) == 0 {
			time.Sleep(time.Millisecond)
			continue
		}
		for _, topic := range topics {
			d.mu.RLock()
			q, ok := d.topicQueues[topic]
			d.mu.RUnlock()
			if !ok {
				continue
			}
			select {
			case e := <-q.ch:
				fmt.Printf("worker %d processed: %s -> %s\n", id, e.Topic, e.Payload)
			default:
			}
		}
	}
}

func (d *Dispatcher) Shutdown() {
	d.cancel()
	d.wg.Wait()
	d.mu.Lock()
	defer d.mu.Unlock()
	for _, q := range d.topicQueues {
		close(q.ch)
	}
}

