	d.Start()

	d.Enqueue(Event{Topic: "temperature", Payload: "25.5"})
	d.Enqueue(Event{Topic: "humidity", Payload: "60%"})
	d.Enqueue(Event{Topic: "temperature", Payload: "26.0"})

	time.Sleep(100 * time.Millisecond)
	d.Shutdown()
	fmt.Println("shutdown complete")
