```javascript
class RegionBuffer {
  constructor(limit) {
    this.queue = [];
    this.limit = limit;
    this.nextSeq = 0;
  }

  enqueue(event) {
    if (this.queue.length >= this.limit) {
      throw new BackpressureError('region buffer full');
    }
    event.seq = this.nextSeq++;
    this.queue.push(event);
    return event;
  }

  dequeue() {
    return this.queue.shift();
  }

  isFull() {
    return this.queue.length >= this.limit;
  }
}

class RegionalFairnessScheduler {
  constructor(regions, weights) {
    this.regionBuffers = new Map();
    this.weights = weights;
    this.counters = new Map();
    this.currentIndex = 0;

    regions.forEach(region => {
      this.regionBuffers.set(region, new RegionBuffer(1000));
      this.counters.set(region, 0);
    });
  }

  schedule() {
    const regions = Array.from(this.regionBuffers.keys());
    const weight = this.weights[regions[this.currentIndex]] || 1;

    if (this.counters.get(regions[this.currentIndex]) < weight) {
      const buffer = this.regionBuffers.get(regions[this.currentIndex]);
      if (buffer.queue.length > 0) {
        this.counters.set(regions[this.currentIndex], 
          this.counters.get(regions[this.currentIndex]) + 1);
        return buffer.dequeue();
      }
    }

    this.currentIndex = (this.currentIndex + 1) % regions.length;
    if (this.counters.get(regions[this.currentIndex]) >= weight) {
      this.counters.set(regions[this.currentIndex], 0);
    }
    return null;
  }
}
