```rust
use crossbeam::channel::{bounded, Sender, Receiver};
use std::sync::{Arc, atomic::{AtomicUsize, AtomicBool, Ordering}};
use std::thread;
use std::collections::HashMap;

const GLOBAL_QUEUE_CAPACITY: usize = 1000;
const LOCAL_QUEUE_CAPACITY: usize = 100;

struct Task {
    id: u64,
    data: Vec<u8>,
    target_node: Option<usize>,
}

struct Scheduler {
    global_sender: Sender<Task>,
    global_receiver: Receiver<Task>,
    local_queues: HashMap<usize, Sender<Task>>,
    shutdown: Arc<AtomicBool>,
}

impl Scheduler {
    fn new(num_nodes: usize) -> Self {
        let (global_sender, global_receiver) = bounded(GLOBAL_QUEUE_CAPACITY);

        let mut local_queues = HashMap::new();
        for node_id in 0..num_nodes {
            let (sender, _) = bounded(LOCAL_QUEUE_CAPACITY);
            local_queues.insert(node_id, sender);
        }

        Self {
            global_sender,
            global_receiver,
            local_queues,
            shutdown: Arc::new(AtomicBool::new(false)),
        }
    }

    fn enqueue(&self, task: Task) -> Result<(), String> {
        if self.shutdown.load(Ordering::SeqCst) {
            return Err("Scheduler shut down".to_string());
        }

        if let Some(node_id) = task.target_node {
            if let Some(local_sender) = self.local_queues.get(&node_id) {
                return local_sender.send(task).map_err(|e| e.to_string());
            }
        }

        self.global_sender.send(task).map_err(|e| e.to_string())
    }

    fn dispatch(&self, node_id: usize) {
        let local_receiver = self.local_queues.get(&node_id).cloned();

        while !self.shutdown.load(Ordering::SeqCst) {
            if let Some(sender) = &local_receiver {
                if let Ok(task) = sender.try_recv() {
                    self.process_task(task);
                    continue;
                }
            }

            if let Ok(task) = self.global_receiver.try_recv() {
                if let Some(target) = task.target_node {
                    if let Some(ns) = self.local_queues.get(&target) {
                        let _ = ns.send(task);
                    }
                } else {
                    let _ = self.local_queues.get(&node_id).map(|s| s.send(task));
                }
            } else {
                thread::sleep(std::time::Duration::from_micros(100));
            }
        }
    }

    fn process_task(&self, task: Task) {
        println!("Processing task {} on current node", task.id);
    }

    fn start_workers(&self, num_nodes: usize, workers_per_node: usize) -> Vec<thread::JoinHandle<()>> {
        let mut handles = Vec::new();

        for node_id in 0..num_nodes {
            for _ in 0..workers_per_node {
                let scheduler = Self {
                    global_sender: self.global_sender.clone(),
                    global_receiver: self.global_receiver.clone(),
                    local_queues: self.local_queues.clone(),
                    shutdown: self.shutdown.clone(),
                };

                let handle = thread::spawn(move || {
                    scheduler.dispatch(node_id);
                });
                handles.push(handle);
            }
        }

        handles
    }

    fn shutdown(&self) {
        self.shutdown.store(true, Ordering::SeqCst);
    }
}

fn main() {
    let scheduler = Scheduler::new(2);
    let handles = scheduler.start_workers(2, 2);

    for i in 0..10 {
        let task = Task {
            id: i,
            data: vec![1, 2, 3],
            target_node: Some(i % 2),
        };
        scheduler.enqueue(task).unwrap();
    }

    thread::sleep(std::time::Duration::from_millis(100));
    scheduler.shutdown();

    for h in handles {
        h.join().unwrap();
    }
}
