```go
package main

import (
	"context"
	"sync"
	"time"
)

type EventType int
const (
	EventTypeMessage EventType = iota
	EventTypeJoin
	EventTypeLeave
)

type Event struct {
	RoomID   string
	EventID  string
	Type     EventType
	Payload  string
	SeqNum   int64
}

type Room struct {
	ID           string
	mu           sync.RWMutex
	buffer       []Event
	capacity     int
	workers      int
	clients      map[chan<- Event]struct{}
	sequenceNum  int64
}

func NewRoom(id string, capacity int) *Room {
	return &Room{
		ID:       id,
		capacity: capacity,
		clients:  make(map[chan<- Event]struct{}),
	}
}

func (r *Room) PushEvent(e Event) bool {
	r.mu.Lock()
	defer r.mu.Unlock()

	if len(r.buffer) >= r.capacity {
		return r.handleBackpressure(e)
	}

	r.buffer = append(r.buffer, e)
	return true
}

func (r *Room) handleBackpressure(e Event) bool {
	if e.Type == EventTypeJoin || e.Type == EventTypeLeave {
		r.buffer = append(r.buffer, e)
		if len(r.buffer) > r.capacity {
			r.buffer = r.buffer[1:]
		}
		return true
	}
	return false
}

func (r *Room) Broadcast(ctx context.Context) {
	ticker := time.NewTicker(10 * time.Millisecond)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			r.mu.RLock()
			if len(r.buffer) == 0 {
				r.mu.RUnlock()
				continue
			}
			event := r.buffer[0]
			r.buffer = r.buffer[1:]
			clients := make([]chan<- Event, 0, len(r.clients))
			for ch := range r.clients {
				clients = append(clients, ch)
			}
			r.mu.RUnlock()

			for _, ch := range clients {
				select {
				case ch <- event:
				default:
				}
			}
		}
	}
}

type Distributor struct {
	mu      sync.RWMutex
	rooms   map[string]*Room
	input   chan Event
	wg      sync.WaitGroup
	ctx     context.Context
	cancel  context.CancelFunc
}

func NewDistributor(bufferPerRoom int) *Distributor {
	ctx, cancel := context.WithCancel(context.Background())
	return &Distributor{
		rooms:  make(map[string]*Room),
		input:  make(chan Event, 10000),
		ctx:    ctx,
		cancel: cancel,
	}
}

func (d *Distributor) GetRoom(roomID string) *Room {
	d.mu.Lock()
	defer d.mu.Unlock()

	if room, ok := d.rooms[roomID]; ok {
		return room
	}

	room := NewRoom(roomID, 1000)
	d.rooms[roomID] = room
	d.wg.Add(1)
	go func() {
		defer d.wg.Done()
		room.Broadcast(d.ctx)
	}()
	return room
}

func (d *Distributor) Run() {
	for {
		select {
		case <-d.ctx.Done():
			return
		case event := <-d.input:
			room := d.GetRoom(event.RoomID)
			room.PushEvent(event)
		}
	}
}

func (d *Distributor) Publish(event Event) {
	select {
	case d.input <- event:
	default:
	}
}

func (d *Distributor) Shutdown() {
	d.cancel()
	close(d.input)
	d.wg.Wait()
}

func main() {
	d := NewDistributor(1000)
	go d.Run()

	d.Publish(Event{
		RoomID:  "room-1",
		EventID: "evt-1",
		Type:    EventTypeJoin,
		Payload: "user-1 joined",
	})

	time.Sleep(100 * time.Millisecond)
	d.Shutdown()
}
```

