// Core types
type LogLevel = 'INFO' | 'WARN' | 'ERROR';
type Log = { teamId: string; severity: LogLevel; timestamp: number; payload: any; seq: number };

// Per-team FIFO buffer with sequence tracking
class TeamBuffer {
  constructor(teamId, capacity) {
    this.teamId = teamId;
    this.buffer = [];  // Circular buffer or ring buffer
    this.seq = 0;       // Monotonic sequence number
    this.criticalSeq = 0;  // Highest preserved ERROR/WARN seq
  }

  push(log) {
    log.seq = this.seq++;
    this.buffer.push(log);
  }

  // Deterministic drop: remove oldest non-critical when over capacity
  prune(threshold) {
    // Keep all ERROR, keep most recent WARN, drop oldest INFO
  }
}

// Global bounded queue with backpressure signal
class LogIngestionPipeline {
  constructor(globalCapacity, backlogThreshold) {
    this.globalQueue = new Map();  // teamId -> TeamBuffer
    this.capacity = globalCapacity;
    this.backlogThreshold = backlogThreshold;
    this.currentBacklog = 0;
  }

  // Backpressure: signal when approaching threshold
  isBacklogged() {
    return this.currentBacklog >= this.backlogThreshold;
  }

  ingest(log) {
    if (!this.globalQueue.has(log.teamId)) {
      this.globalQueue.set(log.teamId, new TeamBuffer(log.teamId));
    }

    const buffer = this.globalQueue.get(log.teamId);

    // Always accept ERROR logs
    if (log.severity === 'ERROR') {
      buffer.push(log);
      this.currentBacklog++;
      return true;
    }

    // Under backlog: accept all
    if (!this.isBacklogged()) {
      buffer.push(log);
      this.currentBacklog++;
      return true;
    }

    // Over backlog: deterministic drop policy
    return buffer.tryAppendWithPruning(log, this.backlogThreshold / this.globalQueue.size);
  }
}
