func NewGameServer(bufferSize, globalCap int) *GameServer {
    return &GameServer{
        clients:    make(map[uint64]chan Event),
        globalQueue: make(chan Event, globalCap),
        tickRate:   16 * time.Millisecond,
    }
}

func (g *GameServer) RegisterClient(id uint64, clientBuffer int) {
    g.clients[id] = make(chan Event, clientBuffer)
}

func (g *GameServer) HandleEvent(clientID uint64, event Event) {
    select {
    case g.clients[clientID] <- event:
    default:
        old := <-g.clients[clientID]
        g.clients[clientID] <- event
    }
}

func (g *GameServer) Run(ctx context.Context) {
    g.running.Store(true)
    ticker := time.NewTicker(g.tickRate)
    defer ticker.Stop()

    for g.running.Load() {
        select {
        case <-ctx.Done():
            g.gracefulShutdown()
            return
        case <-ticker.C:
            g.processTick()
        }
    }
}

func (g *GameServer) processTick() {
    var events []Event
    for len(events) == 0 && len(g.globalQueue) > 0 {
        select {
        case e := <-g.globalQueue:
            events = append(events, e)
        default:
            break
        }
    }

    for i := 0; i < len(g.clients); i++ {
        select {
        case e := <-g.globalQueue:
            events = append(events, e)
        default:
        }
    }

    for _, e := range events {
        g.updateGameState(e)
    }
}

func (g *GameServer) gracefulShutdown() {
    for _, ch := range g.clients {
        for len(ch) > 0 {
            e := <-ch
            g.globalQueue <- e
        }
    }
    close(g.globalQueue)
}

