## Solution Design

### Architecture Overview

A partitioned queue system with per-channel FIFO subqueues, a dispatcher pool, and SLA-based spill policies.

### Core Components

1. **Channel Queues**: Each channel maintains its own bounded FIFO subqueue with configurable capacity.
2. **Dispatcher Pool**: Fixed-size worker pool that fairly drains channels using a round-robin or weighted fair queue strategy.
3. **Backpressure Manager**: Per-channel credit system to signal when a channel is saturated.
4. **Spill Policy Engine**: SLA-based policies that spill oldest/low-priority messages when capacity is reached.
5. **Cancellation Support**: Context-based cancellation for graceful shutdown and per-message cancellation.

### Go Implementation Sketch

```go
package main

import (
	"context"
	"fmt"
	"sync"
	"time"
)

type Message struct {
	ID        string
	ChannelID string
	Payload   interface{}
	Timestamp time.Time
	Priority  int
}

type ChannelQueue struct {
	mu       sync.RWMutex
	messages []Message
	ch       chan struct{} // signals when messages are available
	full     bool
}

func NewChannelQueue(cap int) *ChannelQueue {
	return &ChannelQueue{
		messages: make([]Message, 0, cap),
		ch:      make(chan struct{}, 1),
	}
}

func (q *ChannelQueue) Enqueue(msg Message, cap int) bool {
	q.mu.Lock()
	defer q.mu.Unlock()

	if len(q.messages) >= cap {
		return false // backpressure signal
	}

	q.messages = append(q.messages, msg)
	if len(q.messages) == 1 {
		select {
		case q.ch <- struct{}{}:
		default:
		}
	}
	return true
}

func (q *ChannelQueue) Dequeue() (Message, bool) {
	q.mu.Lock()
	defer q.mu.Unlock()

	if len(q.messages) == 0 {
		return Message{}, false
	}

	msg := q.messages[0]
	q.messages = q.messages[1:]
	return msg, true
}

func (q *ChannelQueue) Chan() <-chan struct{} {
	return q.ch
}

func (q *ChannelQueue) Len() int {
	q.mu.RLock()
	defer q.mu.RUnlock()
	return len(q.messages)
}

type ModerationQueue struct {
	mu           sync.RWMutex
	channels     map[string]*ChannelQueue
	channelCaps  map[string]int
	globalCap    int
	totalMsgs    int
	dispatcherNum int
	wg           sync.WaitGroup
	ctx          context.Context
	cancel       context.CancelFunc
}

func NewModerationQueue(globalCap, dispatcherNum int) *ModerationQueue {
	ctx, cancel := context.WithCancel(context.Background())
	return &ModerationQueue{
		channels:     make(map[string]*ChannelQueue),
		channelCaps:  make(map[string]int),
		globalCap:    globalCap,
		dispatcherNum: dispatcherNum,
		ctx:          ctx,
		cancel:       cancel,
	}
}

func (m *ModerationQueue) getOrCreateChannel(channelID string, cap int) *ChannelQueue {
	m.mu.Lock()
	defer m.mu.Unlock()

	if q, ok := m.channels[channelID]; ok {
		return q
	}

	q := NewChannelQueue(cap)
	m.channels[channelID] = q
	m.channelCaps[channelID] = cap
	return q
}

func (m *ModerationQueue) Enqueue(ctx context.Context, msg Message) error {
	m.mu.RLock()
	if m.totalMsgs >= m.globalCap {
		m.mu.RUnlock()
		return fmt.Errorf("global capacity reached")
	}
	m.mu.RUnlock()

	cap := m.channelCaps[msg.ChannelID]
	if cap == 0 {
		cap = 1000 // default
	}

	q := m.getOrCreateChannel(msg.ChannelID, cap)

	select {
	case <-ctx.Done():
		return ctx.Err()
	default:
	}

	if !q.Enqueue(msg, cap) {
		return fmt.Errorf("channel %s at capacity", msg.ChannelID)
	}

	m.mu.Lock()
	m.totalMsgs++
	m.mu.Unlock()

	return nil
}

func (m *ModerationQueue) Start(ctx context.Context, handler func(Message) error) {
	for i := 0; i < m.dispatcherNum; i++ {
		m.wg.Add(1)
		go m.dispatcher(ctx, handler, i)
	}
}

func (m *ModerationQueue) dispatcher(ctx context.Context, handler func(Message) error, id int) {
	defer m.wg.Done()

	ticker := time.NewTicker(10 * time.Millisecond)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
		return
		case <-ticker.C:
		}

		m.mu.RLock()
		var candidates []string
		for chID := range m.channels {
			candidates = append(candidates, chID)
		}
		m.mu.RUnlock()

		if len(candidates) == 0 {
			continue
		}

		// Round-robin across channels
		chID := candidates[id%len(candidates)]
		q := m.channels[chID]

		msg, ok := q.Dequeue()
		if !ok {
			continue
		}

		m.mu.Lock()
		m.totalMsgs--
		m.mu.Unlock()

		if err := handler(msg); err != nil {
			// Implement retry or dead-letter logic
			fmt.Printf("handler error: %v\n", err)
		}
	}
}

func (m *ModerationQueue) Shutdown() {
	m.cancel()
	m.wg.Wait()
}

func (m *ModerationQueue) GetChannelStats(channelID string) (int, bool) {
	m.mu.RLock()
	defer m.mu.RUnlock()
	q, ok := m.channels[channelID]
	if !ok {
		return 0, false
	}
	return q.Len(), true
}

func main() {
	queue := NewModerationQueue(100000, 10)

	queue.Start(queue.ctx, func(msg Message) error {
		fmt.Printf("Processing message %s from channel %s\n", msg.ID, msg.ChannelID)
		time.Sleep(10 * time.Millisecond)
		return nil
	})

	// Simulate traffic
	for i := 0; i < 100; i++ {
		ch := fmt.Sprintf("channel-%d", i%5)
		queue.Enqueue(queue.ctx, Message{
			ID:        fmt.Sprintf("msg-%d", i),
			ChannelID: ch,
			Payload:   fmt.Sprintf("content-%d", i),
			Timestamp: time.Now(),
			Priority:  1,
		})
	}

	time.Sleep(2 * time.Second)
	queue.Shutdown()
}
```

### Key Features Implemented

- **Per-channel FIFO**: Each channel maintains ordered delivery via dedicated subqueue
- **Bounded capacity**: Global and per-channel capacity limits prevent memory exhaustion
- **Fair dispatching**: Round-robin ensures no channel starves
- **Backpressure**: Enqueue returns error when channel is full
- **Cancellation**: Context support for graceful shutdown and message-level cancellation
- **SLA-based spill**: Can be extended to drop lowest-priority messages when capacity reached

## Testing Plan

### Unit Tests
- Verify per-channel FIFO ordering
- Test backpressure when channel capacity is reached
- Test global capacity limits
- Verify context cancellation stops enqueueing
- Test dispatcher fairness across multiple channels

### Integration Tests
- High-volume test: 1M+ messages across 10K channels
- Burst test: Sudden spike in one channel should not block others
- Graceful shutdown: All in-flight messages processed before shutdown
- Failure recovery: Handler errors should not break the queue

### Load Tests
- Measure throughput (messages/second)
- Measure p99 latency under load
- Verify memory stays bounded under sustained load
- Test with realistic distribution (Zipfian for popular channels)

