## Why This Is Asked

This question tests practical handling of per-entity ordering in a concurrent, dynamic worker pool with backpressure. It mirrors real-world systems at scale, similar to those built at companies like Instacart and Cloudflare.

## Key Concepts

- **Per-partition state and in-order emission**: Each customer (partition) maintains its own sequence counter and buffer to ensure events are processed in order
- **Watermarks for progress tracking**: Track the minimum sequence number across all active partitions to advance the global watermark and handle late events
- **Dynamic rebalancing**: Workers can be added/removed dynamically; partitions must be redistributed without losing in-order guarantees
- **Backpressure mechanisms**: Apply bounded queues and flow control for bursty customers to prevent memory exhaustion

## Implementation Sketch

```javascript
// Per-customer state manager
class PerCustomerState {
  constructor(customerId) {
    this.customerId = customerId;
    this.nextExpectedSeq = 0;
    this.buffer = new Map(); // seq -> event
    this.watermark = 0;
  }

  addEvent(event) {
    this.buffer.set(event.seq, event);
    this.advanceWatermark();
  }

  advanceWatermark() {
    while (this.buffer.has(this.watermark)) {
      this.watermark++;
    }
  }

  getNextEvent() {
    const event = this.buffer.get(this.nextExpectedSeq);
    if (event) {
      this.buffer.delete(this.nextExpectedSeq);
      this.nextExpectedSeq++;
    }
    return event;
  }
}

// Global event router with sharded queues
class EventPipeline {
  constructor(options = {}) {
    this.numShards = options.numShards || 64;
    this.customerStates = new Map();
    this.minHeap = new MinHeap(); // tracks min watermark per customer
    this.maxBufferSize = options.maxBufferSize || 10000;
    this.lateEventPolicy = options.lateEventPolicy || 'delay'; // 'delay', 'drop', 'suppress'
    this.workers = [];
  }

  // Consistent hashing for customer -> shard assignment
  getShard(customerId) {
    return this.hash(customerId) % this.numShards;
  }

  // Route event to appropriate customer state
  async ingest(event) {
    const shard = this.getShard(event.customerId);
    let state = this.customerStates.get(event.customerId);

    if (!state) {
      state = new PerCustomerState(event.customerId);
      this.customerStates.set(event.customerId, state);
      this.minHeap.insert({ customerId: event.customerId, watermark: 0 });
    }

    // Backpressure: check buffer size
    if (state.buffer.size > this.maxBufferSize) {
      await this.applyBackpressure(event.customerId);
    }

    // Handle late/out-of-order events
    return this.handleEvent(state, event);
  }

  handleEvent(state, event) {
    if (event.seq < state.nextExpectedSeq) {
      // Late event - apply policy
      switch (this.lateEventPolicy) {
        case 'drop':
          return { status: 'dropped', reason: 'late' };
        case 'suppress':
          return state.buffer.has(event.seq) 
            ? { status: 'suppressed', reason: 'duplicate' }
            : this.addAndProcess(state, event);
        case 'delay':
        default:
          return this.addAndProcess(state, event);
      }
    }
    return this.addAndProcess(state, event);
  }

  addAndProcess(state, event) {
    state.addEvent(event);
    this.minHeap.update(state.customerId, state.watermark);
    return { status: 'buffered' };
  }

  // Global watermark = minimum across all customer watermarks
  getGlobalWatermark() {
    return this.minHeap.getMin()?.watermark || 0;
  }

  // Process ready events for a customer
  processCustomer(customerId) {
    const state = this.customerStates.get(customerId);
    if (!state) return [];

    const processed = [];
    let event;
    while ((event = state.getNextEvent()) !== undefined) {
      processed.push(this.executeEvent(event));
    }
    return processed;
  }

  async executeEvent(event) {
    // Worker processes the event
    return { customerId: event.customerId, seq: event.seq, result: 'processed' };
  }

  async applyBackpressure(customerId) {
    // Slow down ingestion for bursty customer
    await new Promise(r => setTimeout(r, 100));
  }
}

// Min-heap for tracking customer watermarks
class MinHeap {
  constructor() {
    this.data = [];
    this.indexMap = new Map();
  }

  insert(item) {
    this.data.push(item);
    this.indexMap.set(item.customerId, this.data.length - 1);
    this.bubbleUp(this.data.length - 1);
  }

  update(customerId, watermark) {
    const idx = this.indexMap.get(customerId);
    if (idx !== undefined) {
      this.data[idx].watermark = watermark;
      this.bubbleUp(idx);
      this.bubbleDown(idx);
    }
  }

  getMin() {
    return this.data[0];
  }

  bubbleUp(idx) {
    // ... standard heap operations
  }

  bubbleDown(idx) {
    // ... standard heap operations
  }
}
```

## Runtime Policy for Late Events

| Policy | Behavior | Use Case |
|--------|----------|----------|
| **Delay** | Buffer late events until sequence is complete | When all events must be processed (e.g., financial transactions) |
| **Suppress** | Drop duplicates, keep first occurrence | When idempotency is guaranteed (e.g., cache updates) |
| **Drop** | Immediately discard late events | When recent state is more important than completeness (e.g., real-time dashboards) |

