questions.answer:
Implement per-device FIFO buffers chained through a bounded global queue with a sequencer to assign monotonic epochs per device. Transformers use work-stealing with local queues to maintain per-device ordering while maximizing throughput. Each worker pulls from the global queue, extracts the device_id, and processes records in epoch order per device. The Aggregator stage maintains separate sliding windows per device, computing 1-minute moving averages using a timestamp-based eviction policy.

```javascript
class BoundedStreamProcessor {
  constructor(config) {
    this.maxQueueSize = config.maxQueueSize || 10000;
    this.transformerCount = config.transformers || 4;
    this.aggregatorCount = config.aggregators || 2;
    this.backlogThreshold = config.backlogThreshold || 100;
    this.windowSizeMs = 60000;

    this.globalQueue = new RingBuffer(this.maxQueueSize);
    this.deviceBuffers = new Map();
    this.deviceEpochs = new Map();
    this.deviceBacklogs = new Map();
    this.pausedDevices = new Set();
    this.transformerWorkers = [];
    this.aggregatorWorkers = [];
    this.running = false;
  }

  start() {
    this.running = true;
    for (let i = 0; i < this.transformerCount; i++) {
      this.transformerWorkers.push(this.spawnTransformer(i));
    }
    for (let i = 0; i < this.aggregatorCount; i++) {
      this.aggregatorWorkers.push(this.spawnAggregator(i));
    }
  }

  async ingest(record) {
    const { device_id } = record;
    if (this.pausedDevices.has(device_id)) {
      await this.waitForResume(device_id);
    }
    this.checkBacklog(device_id);
    this.globalQueue.push(record);
  }

  checkBacklog(device_id) {
    const backlog = this.deviceBacklogs.get(device_id) || 0;
    if (backlog > this.backlogThreshold && !this.pausedDevices.has(device_id)) {
      this.pausedDevices.add(device_id);
      this.emitBackpressureEvent(device_id, 'paused');
    }
  }

  waitForResume(device_id) {
    return new Promise(resolve => {
      const check = setInterval(() => {
        if (!this.pausedDevices.has(device_id)) {
          clearInterval(check);
          resolve();
        }
      }, 100);
    });
  }

  spawnTransformer(id) {
    return setInterval(() => {
      const record = this.globalQueue.pop();
      if (!record) return;

      const epoch = this.assignEpoch(record.device_id);
      const transformed = { ...record, epoch, processedAt: Date.now() };
      this.forwardToAggregator(transformed);
    }, 0);
  }

  assignEpoch(device_id) {
    const current = this.deviceEpochs.get(device_id) || 0;
    const next = current + 1;
    this.deviceEpochs.set(device_id, next);
    return next;
  }

  forwardToAggregator(record) {
    const buffer = this.deviceBuffers.get(record.device_id) || [];
    buffer.push(record);
    this.deviceBuffers.set(record.device_id, buffer);
  }

  spawnAggregator(id) {
    return setInterval(() => {
      this.deviceBuffers.forEach((records, device_id) => {
        if (records.length === 0) return;
        const sorted = records.sort((a, b) => a.epoch - b.epoch);
        const window = this.computeMovingAverage(sorted);
        this.emitAggregation(device_id, window);
        this.deviceBuffers.set(device_id, []);
        this.updateBacklog(device_id);
      });
    }, 1000);
  }

  computeMovingAverage(records) {
    const now = Date.now();
    const windowStart = now - this.windowSizeMs;
    const inWindow = records.filter(r => r.ts >= windowStart);
    if (inWindow.length === 0) return null;
    const sum = inWindow.reduce((acc, r) => acc + r.value, 0);
    return sum / inWindow.length;
  }

  updateBacklog(device_id) {
    const backlog = (this.deviceBuffers.get(device_id) || []).length;
    this.deviceBacklogs.set(device_id, backlog);
    if (backlog < this.backlogThreshold && this.pausedDevices.has(device_id)) {
      this.pausedDevices.delete(device_id);
      this.emitBackpressureEvent(device_id, 'resumed');
    }
  }

  resizeWorkers(transformers, aggregators) {
    this.transformerCount = transformers;
    this.aggregatorCount = aggregators;
    this.transformerWorkers.forEach(w => clearInterval(w));
    this.aggregatorWorkers.forEach(w => clearInterval(w));
    if (this.running) this.start();
  }

  emitBackpressureEvent(device_id, status) {
    console.log(`Device ${device_id} ${status}`);
  }

  emitAggregation(device_id, avg) {
    console.log(`Device ${device_id} avg: ${avg}`);
  }
}

class RingBuffer {
  constructor(capacity) {
    this.capacity = capacity;
    this.buffer = new Array(capacity);
    this.head = 0;
    this.tail = 0;
    this.size = 0;
  }

  push(item) {
    if (this.size >= this.capacity) {
      throw new Error('Queue overflow');
    }
    this.buffer[this.tail] = item;
    this.tail = (this.tail + 1) % this.capacity;
    this.size++;
  }

  pop() {
    if (this.size === 0) return null;
    const item = this.buffer[this.head];
    this.head = (this.head + 1) % this.capacity;
    this.size--;
    return item;
  }
}

module.exports = { BoundedStreamProcessor };
```

**Test Plan:**

1. **Unit Tests**
   - RingBuffer: Test push/pop boundaries, overflow/underflow handling
   - Epoch assignment: Verify monotonic increment per device_id
   - Moving average: Verify 1-minute window calculation with timestamp filtering

2. **Integration Tests**
   - End-to-end flow: Submit records through ingest -> transformer -> aggregator
   - Per-device ordering: Verify epoch ordering is preserved across stages
   - Backpressure: Submit burst traffic exceeding backlog threshold; verify device pausing and resumption
   - Dynamic resizing: Call resizeWorkers at runtime; verify workers restart with new counts

3. **Stress Tests**
   - High throughput: Simulate many producers with varying device_ids
   - Memory bounds: Verify queue size stays within maxQueueSize
   - Fairness: Confirm low-volume devices make progress when high-volume device is paused

