## Code Example
```go
type Event struct {
    Source   string
    Time     time.Time
    Payload  []byte
    Seq      uint64
}

type SpillEntry struct {
    File    string
    Offset  int64
    Key     string
}

type Engine struct {
    sources      map[string]*SourceChannel
    watermark     time.Time
    maxBuffered   int
    spillDir      string
    credits       map[string]int
    mu            sync.RWMutex
}

func (e *Engine) AddSource(id string) {
    e.sources[id] = &SourceChannel{
        queue:   NewRingBuffer(e.maxBuffered),
        seq:     0,
        pending: make([]*Event, 0),
    }
}

func (e *Engine) Receive(evt Event) error {
    e.mu.RLock()
    credits := e.credits[evt.Source]
    e.mu.RUnlock()

    if credits <= 0 {
        return ErrBackpressure
    }

    ch := e.sources[evt.Source]
    if ch.queue.IsFull() {
        e.spillToDisk(evt)
    } else {
        ch.queue.Push(evt)
    }

    e.mu.Lock()
    e.credits[evt.Source]--
    e.mu.Unlock()
    return nil
}

func (e *Engine) AdvanceWatermark(t time.Time) {
    e.mu.Lock()
    e.watermark = t
    e.mu.Unlock()

    for _, ch := range e.sources {
        ch.flushSpilled()
    }
}

func (e *Engine) Process() {
    for _, ch := range e.sources {
        for {
            evt := ch.queue.Peek()
            if evt == nil || evt.Time.After(e.watermark) {
                break
            }
            ch.queue.Pop()
            ch.emit(evt)
        }
    }
}
```

