```javascript
class VehiclePipeline {
  constructor(vehicleCount, bufferSize, allowedLateness) {
    this.queues = new Map(); // vehicle_id -> PriorityQueue
    this.buffers = new Map(); // vehicle_id -> CircularBuffer
    this.watermarks = new Map(); // vehicle_id -> timestamp
    this.sequenceNumbers = new Map(); // vehicle_id -> counter
    this.allowedLateness = allowedLateness;
  }

  enqueue(vehicleId, event) {
    const seq = this.sequenceNumbers.get(vehicleId) || 0;
    event.seq = seq;
    this.queues.get(vehicleId).push(event);
    this.sequenceNumbers.set(vehicleId, seq + 1);
    this.updateWatermark(vehicleId);
  }

  updateWatermark(vehicleId) {
    const processed = this.buffers.get(vehicleId).latest();
    const watermark = processed ? processed.ts : Date.now();
    this.watermarks.set(vehicleId, watermark - this.allowedLateness);
  }

  isLate(vehicleId, event) {
    const watermark = this.watermarks.get(vehicleId);
    return event.ts < watermark;
  }

  backpressure(source) {
    const pressureLevel = this.getBufferUtilization();
    source.throttle(pressureLevel);
  }
}

class StatefulFusion {
  constructor(windowSize) {
    this.windowSize = windowSize;
    this.state = new Map(); // vehicle_id -> WindowState
  }

  process(vehicleId, event) {
    let state = this.state.get(vehicleId) || new WindowState();
    state.add(event);
    state.evictOlderThan(this.windowSize);
    return this.smooth(state);
  }

  smooth(state) {
    const positions = state.events.map(e => e.position);
    return this.kalmanFilter(positions);
  }
}

class AnomalyScorer {
  score(vehicleId, fusedState) {
    const velocity = fusedState.velocity;
    const threshold = this.baseline.get(vehicleId) * 1.5;
    return Math.abs(velocity) > threshold ? 'ALERT' : 'NORMAL';
  }
}
```

