## Code Example
```java
import java.util.concurrent.*;
import java.util.*;

public class BoundedFairDispatcher {
  static class Order { final String id; Order(String id){ this.id = id; } }
  private final int perProducerCap;
  private final Map<String,BlockingQueue<Order>> queues = new ConcurrentHashMap<>();
  private final BlockingQueue<Order> ring;
  private volatile boolean shutdown = false;
  public BoundedFairDispatcher(int perProducerCap, int ringCap){ this.perProducerCap = perProducerCap; this.ring = new ArrayBlockingQueue<>(ringCap); }
  public void enqueue(String pid, Order o) throws InterruptedException {
    BlockingQueue<Order> q = queues.computeIfAbsent(pid, k -> new ArrayBlockingQueue<>(perProducerCap));
    q.put(o); // producer blocks if quota reached
  }
  public void dispatcherLoop() throws InterruptedException {
    while (!shutdown) {
      for (BlockingQueue<Order> q : queues.values()) {
        Order o = q.poll();
        if (o != null) ring.put(o);
      }
      // simple backoff to avoid busy spin
      Thread.yield();
    }
  }
  public void shutdown() { shutdown = true; }
}
```

