Architect a dispatcher that feeds per-merchant FIFO queues from a global bounded buffer with dynamic backpressure propagation. Each merchant maintains a sequence number and a durable replay log to enable deterministic replay after crashes. Implement an LRU spill store for evicted non-critical events with a priority fast-path for latency-sensitive events. Support cancellation and graceful shutdown with proper resource cleanup.

```java
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class FraudDetectionPipeline {
    private final int maxQueueDepth;
    private final ConcurrentHashMap<String, MerchantFifoQueue> merchantQueues = new ConcurrentHashMap<>();
    private final LruSpillStore spillStore = new LruSpillStore(10000);
    private final PriorityBlockingQueue<Event> fastPath = new PriorityBlockingQueue<>();
    private final AtomicBoolean shuttingDown = new AtomicBoolean(false);
    private final ExecutorService dispatcherExecutor, processorExecutor;

    public record Event(String merchantId, long seqNum, EventType type, Object payload) {
        public boolean isHighPriority() { return type == EventType.FRAUD_ALERT; }
    }
    public enum EventType { NORMAL, FRAUD_ALERT, AUDIT }

    public record MerchantFifoQueue(String merchantId, AtomicLong seqNum, LinkedBlockingQueue<Event> queue) {}

    public void submit(Event event) throws RejectedExecutionException {
        if (shuttingDown.get()) throw new RejectedExecutionException("Pipeline shutting down");
        if (event.isHighPriority()) {
            fastPath.offer(event);
        } else if (totalQueueDepth() >= maxQueueDepth) {
            if (!event.isHighPriority()) {
                spillStore.evictAndStore(event);
            }
        } else {
            merchantQueues.computeIfAbsent(event.merchantId(), 
                id -> new MerchantFifoQueue(id, new AtomicLong(0), new LinkedBlockingQueue<>()))
                .queue().offer(event);
        }
    }

    public List<Event> replayFromCheckpoint(String merchantId, long fromSeqNum) {
        return spillStore.getEventsForMerchant(merchantId).stream()
            .filter(e -> e.seqNum() >= fromSeqNum)
            .sorted(Comparator.comparing(Event::seqNum))
            .toList();
    }

    public void shutdown() {
        shuttingDown.set(true);
        dispatcherExecutor.shutdown();
        processorExecutor.shutdown();
    }
}

class LruSpillStore extends LinkedHashMap<String, List<Event>> {
    private final int capacity;
    public LruSpillStore(int capacity) { super(16, 0.75f, true); this.capacity = capacity; }
    protected boolean removeEldestEntry(Map.Entry eldest) { return size() > capacity; }
    public void evictAndStore(Event event) { computeIfAbsent(event.merchantId(), k -> new ArrayList<>()).add(event); }
    public List<Event> getEventsForMerchant(String merchantId) { return getOrDefault(merchantId, List.of()); }
}
```

