## Code Example

```javascript
class DAGScheduler {
  constructor(options = {}) {
    this.maxQueueSize = options.maxQueueSize || 10000;
    this.numWorkers = options.initialWorkers || 4;
    this.workers = [];
    this.globalQueue = [];
    this.tenantQuotas = new Map();
    this.inDegree = new Map();
    this.pendingTasks = new Map();
  }

  submitDAG(dag, tenantId) {
    if (this.globalQueue.length >= this.maxQueueSize) {
      throw new Error('Backpressure: queue at capacity');
    }
    this.initDAGState(dag);
    this.globalQueue.push({ dag, tenantId, readyTasks: this.getReadyTasks(dag) });
    this.processQueue();
  }

  initDAGState(dag) {
    this.inDegree.set(dag.id, new Map());
    this.pendingTasks.set(dag.id, new Set(dag.tasks.map(t => t.id)));
    for (const task of dag.tasks) {
      this.inDegree.get(dag.id).set(task.id, task.dependencies.length);
    }
  }

  getReadyTasks(dag) {
    return dag.tasks.filter(t => this.inDegree.get(dag.id).get(t.id) === 0);
  }

  processQueue() {
    const tenantOrder = this.fairRoundRobin();
    for (const tenantId of tenantOrder) {
      const entry = this.globalQueue.find(e => e.tenantId === tenantId && e.readyTasks.length > 0);
      if (entry) {
        const task = entry.readyTasks.shift();
        this.assignToWorker(task, entry.dag);
      }
    }
  }

  assignToWorker(task, dag) {
    const worker = this.getIdleWorker();
    if (!worker) {
      this.scaleUp();
    }
    worker.execute(task, {
      onComplete: () => this.onTaskComplete(task, dag),
      onRetry: () => this.scheduleRetry(task, dag),
      onFailure: (err) => this.onTaskFailure(task, dag, err)
    });
  }

  onTaskComplete(task, dag) {
    this.pendingTasks.get(dag.id).delete(task.id);
    for (const dependent of dag.getDependents(task.id)) {
      const newDegree = this.inDegree.get(dag.id).get(dependent.id) - 1;
      this.inDegree.get(dag.id).set(dependent.id, newDegree);
      if (newDegree === 0) {
        const entry = this.globalQueue.find(e => e.dag.id === dag.id);
        entry.readyTasks.push(dependent);
      }
    }
    this.processQueue();
  }

  scheduleRetry(task, dag, attempt = 1, maxAttempts = 3) {
    if (attempt > maxAttempts) {
      return this.onTaskFailure(task, dag, new Error('Max retries exceeded'));
    }
    const delay = Math.pow(2, attempt) * 1000;
    setTimeout(() => this.assignToWorker(task, dag), delay);
  }

  onTaskFailure(task, dag, err) {
    console.error(`Task ${task.id} failed:`, err);
    dag.onTaskFailed?.(task, err);
  }

  getIdleWorker() {
    return this.workers.find(w => w.status === 'idle');
  }

  scaleUp() {
    if (this.workers.length < this.numWorkers * 2) {
      this.workers.push(new Worker(this));
    }
  }

  fairRoundRobin() {
    return Array.from(this.tenantQuotas.keys());
  }
}
```

