// Central Arbiter with Per-Customer Lanes and Credit-Based Backpressure

class EventRouter {
  constructor(config) {
    this.maxQueueSize = config.maxQueueSize || 10000;
    this.creditBudget = config.creditBudget || 100;
    this.lanes = new Map();
    this.sequenceCounters = new Map();
  }

  // Acquire credit for a customer before enqueueing
  acquireCredit(customerId) {
    const credits = this.lanes.get(customerId)?.credits || this.creditBudget;
    if (credits <= 0) {
      return false; // Apply backpressure
    }
    if (this.lanes.has(customerId)) {
      this.lanes.get(customerId).credits--;
    } else {
      this.lanes.set(customerId, { credits: credits - 1, queue: [] });
      this.sequenceCounters.set(customerId, 0);
    }
    return true;
  }

  // Enqueue event with sequence tracking
  enqueue(customerId, ts, payload) {
    if (!this.acquireCredit(customerId)) {
      throw new Error('Backpressure applied: insufficient credits');
    }
    const lane = this.lanes.get(customerId);
    const seq = ++this.sequenceCounters.get(customerId);
    lane.queue.push({ customerId, ts, payload, seq });
  }

  // Replenish credits after processing
  replenishCredit(customerId, count = 1) {
    const lane = this.lanes.get(customerId);
    if (lane) {
      lane.credits = Math.min(lane.credits + count, this.creditBudget);
    }
  }

  // Process lane with in-order delivery guarantee
  processLane(customerId, stage1Fn, stage2Fn) {
    const lane = this.lanes.get(customerId);
    if (!lane || lane.queue.length === 0) return;

    const event = lane.queue[0];
    const enriched = stage1Fn(event); // Stage 1: Validation/Enrichment
    const aggregated = stage2Fn(enriched); // Stage 2: Aggregation
    lane.queue.shift();
    this.replenishCredit(customerId);
    return aggregated;
  }
}

// Dynamic Worker Pool with Work-Stealing
class WorkerPool {
  constructor(router, workerCount) {
    this.router = router;
    this.workers = [];
    this.globalQueue = [];
    this.epoch = 0;
    this.resize(workerCount);
  }

  resize(newCount) {
    this.epoch++; // Increment epoch for safe cleanup
    while (this.workers.length < newCount) {
      this.addWorker();
    }
    while (this.workers.length > newCount) {
      this.removeWorker();
    }
  }

  addWorker() {
    const id = this.workers.length;
    const worker = {
      id,
      localQueue: [],
      running: true,
      epoch: this.epoch
    };
    this.workers.push(worker);
    this.runWorker(worker);
  }

  removeWorker() {
    const worker = this.workers.pop();
    worker.running = false;
    // Migrate local queue to global queue (epoch-based cleanup)
    this.globalQueue.push(...worker.localQueue.filter(e => e.epoch === this.epoch));
  }

  runWorker(worker) {
    const process = () => {
      if (!worker.running || worker.epoch !== this.epoch) return;

      let event = worker.localQueue.pop();
      if (!event && this.globalQueue.length > 0) {
        // Work-stealing from global queue
        event = this.globalQueue.shift();
      }

      if (event) {
        this.router.processLane(event.customerId, 
          e => ({ ...e, validated: true }),
          e => ({ ...e, aggregated: true })
        );
      }

      setImmediate(process);
    };
    process();
  }
}

// Late Event Policy
class LateEventPolicy {
  constructor(config) {
    this.ttlMs = config.ttlMs || 300000; // 5 minutes default
    this.policy = config.policy || 'reject'; // reject | log | deadLetter
    this.deadLetterQueue = [];
  }

  isLate(ts) {
    return Date.now() - ts > this.ttlMs;
  }

  handle(event) {
    if (this.isLate(event.ts)) {
      switch (this.policy) {
        case 'log':
          console.warn('Late event received:', event);
          return null;
        case 'deadLetter':
          this.deadLetterQueue.push(event);
          return null;
        case 'reject':
        default:
          throw new Error(`Late event rejected: ${event.customerId}`);
      }
    }
    return event;
  }
}
```

