```go
package main

import (
  "time"
  "sync"
)

type Event struct { User string; TS time.Time }
type Summary struct { User string; Count int }

func boundWindowWorker(in <-chan Event, out chan<- Summary, window time.Duration) {
  mu := sync.Mutex{}
  perUser := make(map[string][]time.Time)
  tick := time.NewTicker(1 * time.Second)
  defer tick.Stop()

  for {
    select {
    case e := <-in:
      mu.Lock()
      arr := perUser[e.User]
      arr = append(arr, e.TS)
      cutoff := e.TS.Add(-window)
      i := 0
      for i < len(arr) && arr[i].Before(cutoff) {
        i++
      }
      perUser[e.User] = arr[i:]
      mu.Unlock()
    case t := <-tick.C:
      _ = t
      mu.Lock()
      for u, arr := range perUser {
        out <- Summary{User: u, Count: len(arr)}
      }
      mu.Unlock()
    }
  }
}
```

