```javascript
class TenantState {
  constructor(tenantId) {
    this.tenantId = tenantId;
    this.nextSeq = 0;
    this.buffer = new Map();
    this.watermark = null;
  }
}

class BoundedQueue {
  constructor(capacity) {
    this.capacity = capacity;
    this.items = [];
    this.waitingProducers = [];
    this.waitingConsumers = [];
  }

  async offer(item) {
    if (this.items.length >= this.capacity) {
      return new Promise(resolve => this.waitingProducers.push({ item, resolve }));
    }
    this.items.push(item);
    this.notifyConsumers();
    return true;
  }

  async take() {
    if (this.items.length === 0) {
      return new Promise(resolve => this.waitingConsumers.push(resolve));
    }
    const item = this.items.shift();
    this.notifyProducers();
    return item;
  }

  notifyConsumers() {
    if (this.waitingConsumers.length > 0 && this.items.length > 0) {
      this.waitingConsumers.shift()(this.items.shift());
    }
  }

  notifyProducers() {
    if (this.waitingProducers.length > 0 && this.items.length < this.capacity) {
      const { item, resolve } = this.waitingProducers.shift();
      this.items.push(item);
      resolve(true);
    }
  }

  get size() { return this.items.length; }
}

class IngestStage {
  async process(item) { return item; }
}

class TransformStage {
  async process(item) { return item; }
}

class SinkStage {
  async process(item) { return item; }
}

class BoundedPipeline {
  constructor({ queueCapacity, workersPerStage, lateEventPolicy }) {
    this.queue = new BoundedQueue(queueCapacity);
    this.stages = [new IngestStage(), new TransformStage(), new SinkStage()];
    this.tenantStates = new Map();
    this.latePolicy = lateEventPolicy;
    this.workerPool = [];
    this.scaleWorkers(workersPerStage);
  }

  async process(tenantId, event) {
    const state = this.getOrCreateTenant(tenantId);
    if (this.isLate(event, state)) {
      return this.latePolicy.handle(event, state);
    }
    const item = { tenantId, event, seq: state.nextSeq++ };
    await this.queue.offer(item);
    this.scheduleProcessing();
  }

  isLate(event, state) {
    if (!state.watermark) return false;
    const threshold = this.latePolicy.retentionMs;
    return event.opTime < state.watermark - threshold;
  }

  getOrCreateTenant(tenantId) {
    if (!this.tenantStates.has(tenantId)) {
      this.tenantStates.set(tenantId, new TenantState(tenantId));
    }
    return this.tenantStates.get(tenantId);
  }

  scaleWorkers(count) {
    this.workerPool = Array.from({ length: count }, () => ({
      stages: this.stages,
      process: async (item) => {
        for (const stage of this.stages) {
          item = await stage.process(item);
        }
        return item;
      }
    }));
    return this.workerPool;
  }

  async scheduleProcessing() {
    const item = await this.queue.take();
    const state = this.tenantStates.get(item.tenantId);
    const worker = this.getNextWorker(item.tenantId);
    await worker.process(item);
    state.watermark = item.event.opTime;
  }

  getNextWorker(tenantId) {
    const hash = tenantId.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0);
    return this.workerPool[hash % this.workerPool.length];
  }
}

