## Complete Solution

### Data Structures

```javascript
// Concrete implementation in TypeScript-like pseudocode

interface Task {
  id: string;
  tenant_id: string;
  priority: number;        // 1-10, higher = more urgent
  deadline: number;        // Unix timestamp
  created_at: number;
  payload: any;
}

class TenantQueue {
  private queue: Task[] = [];
  private lock = new Mutex();

  async enqueue(task: Task): Promise<boolean> {
    await this.lock.acquire();
    try {
      if (this.queue.length >= MAX_PER_TENANT) return false;
      this.queue.push(task);
      this.queue.sort((a, b) => this.effectivePriority(b) - this.effectivePriority(a));
      return true;
    } finally { this.lock.release(); }
  }

  async dequeue(): Promise<Task | null> {
    await this.lock.acquire();
    try { return this.queue.shift() ?? null; }
    finally { this.lock.release(); }
  }

  isEmpty(): boolean { return this.queue.length === 0; }

  private effectivePriority(task: Task): number {
    const waitTime = Date.now() - task.created_at;
    const agingBoost = Math.floor(waitTime / AGING_INTERVAL_MS) * AGING_FACTOR;
    return task.priority + agingBoost;
  }
}

class GlobalScheduler {
  private tenantQueues = new Map<string, TenantQueue>();
  private semaphore: Semaphore;
  private priorityHeap: Heap<TenantQueue>;  // Max-heap by effective priority

  constructor(
    private maxGlobalTasks: number,
    private maxPerTenant: number
  ) {
    this.semaphore = new Semaphore(maxGlobalTasks);
    this.priorityHeap = new Heap((a, b) => this.compareQueues(a, b));
  }

  async enqueue(task: Task): Promise<boolean> {
    // Backpressure: wait for capacity
    await this.semaphore.acquire();

    let tenantQueue = this.tenantQueues.get(task.tenant_id);
    if (!tenantQueue) {
      tenantQueue = new TenantQueue();
      this.tenantQueues.set(task.tenant_id, tenantQueue);
    }

    const success = await tenantQueue.enqueue(task);
    if (!success) {
      this.semaphore.release();
      return false;
    }

    // Re-heapify: tenant may now be non-empty
    this.priorityHeap.insert(tenantQueue);
    return true;
  }

  async dequeue(): Promise<Task | null> {
    // Find highest-priority non-empty queue
    while (!this.priorityHeap.isEmpty()) {
      const candidate = this.priorityHeap.peek();
      const task = await candidate.dequeue();

      if (task) {
        this.semaphore.release();
        // Re-heapify if still non-empty
        if (!candidate.isEmpty()) {
          this.priorityHeap.replace(candidate);
        } else {
          this.priorityHeap.extract();
        }
        return task;
      }
      this.priorityHeap.extract();  // Remove empty queue
    }
    return null;
  }

  private compareQueues(a: TenantQueue, b: TenantQueue): number {
    // Compare by head task's effective priority
    const priA = a.getHeadEffectivePriority();
    const priB = b.getHeadEffectivePriority();
    return priA - priB;
  }
}
```

### Aging Implementation

```javascript
const AGING_INTERVAL_MS = 5000;    // Boost every 5 seconds
const AGING_FACTOR = 1;            // Priority boost per interval
const MAX_AGING_BOOST = 10;        // Cap to prevent unbounded promotion

// Effective priority formula:
// effective = original_priority + min(floor(wait_time / INTERVAL), MAX) * FACTOR
// This ensures no tenant waits indefinitely while high-priority tasks still get served first
```

### Worker Pool

```javascript
class WorkerPool {
  private workers: Worker[] = [];

  constructor(private scheduler: GlobalScheduler, numWorkers: number) {
    for (let i = 0; i < numWorkers; i++) {
      this.workers.push(this.workerLoop(i));
    }
  }

  private async workerLoop(id: number) {
    while (true) {
      const task = await this.scheduler.dequeue();
      if (task) await this.processTask(task);
      else await this.sleep(10);  // Backoff when empty
    }
  }

  private async processTask(task: Task) {
    // Image processing logic
  }
}
```

### Trade-offs

| Aspect | Choice | Trade-off |
|--------|--------|-----------|
| Priority queue | Heap vs sorted list | O(log n) vs O(n) dequeue; heap needs reheapify on changes |
| Aging strategy | Linear boost | Simple but may over-promote; exponential could be fairer |
| Backpressure | Semaphore | Blocks producers; alternatively return error for pushback |
| Per-tenant bound | Hard limit | Prevents tenant monopoly; may waste capacity if one tenant idle |
| Locking | Per-queue mutex | Good concurrency; alternatives: lock-free (more complex) |

