// Test 4: Backpressure under burst load
async function testBackpressure() {
  const scheduler = new GlobalScheduler(10, 20);
  const results = [];

  // Try to enqueue 1000 tasks rapidly
  const promises = Array(1000).fill(0).map((_, i) => 
    scheduler.enqueue({tenant_id: `t${i % 10}`, priority: 5, ...})
      .then(r => results.push(r))
  );

  await Promise.all(promises);
  const accepted = results.filter(r => r).length;
  assert(accepted <= 10 + 200); // Global + per-tenant capacity
}

// Test 5: Cross-tenant fairness under contention
async function testFairness() {
  const scheduler = new GlobalScheduler(1000, 100);
  const tenantCounts = {};

  // Submit equal load from 10 tenants
  for (let i = 0; i < 10; i++) {
    for (let j = 0; j < 100; j++) {
      await scheduler.enqueue({tenant_id: `t${i}`, priority: 5, ...});
    }
  }

  // Process all tasks and count per tenant
  for (let i = 0; i < 1000; i++) {
    const task = await scheduler.dequeue();
    tenantCounts[task.tenant_id] = (tenantCounts[task.tenant_id] || 0) + 1;
  }

  // All tenants should have roughly equal processing (within 20%)
  const counts = Object.values(tenantCounts);
  const avg = counts.reduce((a, b) => a + b) / counts.length;
  const maxDeviation = Math.max(...counts.map(c => Math.abs(c - avg) / avg));
  assert(maxDeviation < 0.2);
}

// Test 6: Liveness under bursty load (simulated DDoS)
async function testBurstyLoadLiveness() {
  const scheduler = new GlobalScheduler(50, 20);
  let completed = 0;
  const workers = 10;

  // Simulate burst: 500 tasks in 100ms
  const burst = async () => {
    for (let i = 0; i < 500; i++) {
      await scheduler.enqueue({tenant_id: `t${i % 5}`, priority: Math.random() * 10, ...});
    }
  };

  // Workers continuously process
  const process = async () => {
    while (completed < 500) {
      const task = await scheduler.dequeue();
      if (task) { completed++; await simulateWork(1); }
    }
  };

  await Promise.all([burst(), ...Array(workers).fill(process)]);
  assert(completed === 500);  // All tasks completed - no deadlock
}
```

