class RoomBuffer {
  constructor(maxBacklog = 1000) {
    this.queues = new Map();
    this.maxBacklog = maxBacklog;
  }

  enqueue(room, event) {
    if (!this.queues.has(room)) {
      this.queues.set(room, []);
    }
    const queue = this.queues.get(room);
    if (queue.length >= this.maxBacklog) {
      if (event.type === 'typing') {
        return this.coalesceTyping(room, event);
      }
      return false; // backpressure signal
    }
    queue.push({ ...event, seq: this.getNextSeq(room) });
    return true;
  }

  coalesceTyping(room, event) {
    const queue = this.queues.get(room);
    const last = queue[queue.length - 1];
    if (last?.type === 'typing') {
      last.count = (last.count || 1) + 1;
      return true;
    }
    queue.push({ ...event, count: 1 });
    return true;
  }
}
```

This implementation provides per-room ordering via sequence numbers, backpressure via bounded queue depth, and automatic coalescing of typing events during high load.

