  Device string
  Seq    int
  Data   string
}

// global bounded queue
var globalQueue = make(chan Event, 128)

var (
  mu     sync.Mutex
  queues = map[string]chan Event{}
  seen   = map[string]struct{}{}
)

func getQueue(id string) chan Event {
  mu.Lock()
  defer mu.Unlock()
  q, ok := queues[id]
  if !ok {
    q = make(chan Event, 32)
    queues[id] = q
  }
  return q
}

func dispatcher() {
  for e := range globalQueue {
    key := e.Device + ":" + strconv.Itoa(e.Seq)
    mu.Lock()
    if _, ok := seen[key]; ok {
      mu.Unlock()
      continue
    }
    seen[key] = struct{}{}
    ch := getQueue(e.Device)
    mu.Unlock()
    ch <- e
  }
}

// workers would range over device queues in round-robin
