// Minimal sketch: two-level queues
#include <atomic>
#include <vector>
#include <queue>
#include <unordered_map>
#include <mutex>
#include <string>

struct Slot { std::string data; bool used; };

class Ring {
  std::vector<Slot> buf;
  std::atomic<size_t> head, tail;
public:
  Ring(size_t n): buf(n), head(0), tail(0) {}
  bool try_enqueue(const std::string& s){
    size_t h = head.load(std::memory_order_relaxed);
    size_t t = tail.load(std::memory_order_acquire);
    if ((t - h) >= buf.size()) return false;
    buf[t % buf.size()] = {s,true};
    tail.store(t+1, std::memory_order_release);
    return true;
  }
  bool try_dequeue(std::string& out){
    size_t h = head.load(std::memory_order_acquire);
    size_t t = tail.load(std::memory_order_relaxed);
    if (h==t) return false;
    out = buf[h % buf.size()].data;
    head.store(h+1, std::memory_order_release);
    return true;
  }
};

class Dispatcher {
  Ring ring;
  std::unordered_map<std::string, std::queue<std::string>> topicQueues;
  std::mutex m;
public:
  Dispatcher(size_t n): ring(n) {}
  bool enqueue(const std::string& topic, const std::string& data){
    if (!ring.try_enqueue(topic + ":" + data)) return false;
    std::lock_guard<std::mutex> lg(m);
    topicQueues[topic].push(data);
    return true;
  }
  bool dequeue(std::string& outTopicData){
    std::lock_guard<std::mutex> lg(m);
    for (auto &kv : topicQueues){
      if (!kv.second.empty()){
        outTopicData = kv.first + ":" + kv.second.front();
        kv.second.pop();
        return true;
      }
    }
    return false;
  }
};
```

