package main

type Event struct {
    ID      string
    ShardID int
    Data    []byte
}

type ShardProcessor struct {
    queue   chan Event
    worker  func(Event)
    done    chan struct{}
}

type ConcurrentProcessor struct {
    shards    []*ShardProcessor
    shardCount int
}

func NewConcurrentProcessor(shardCount int, queueSize int, worker func(Event)) *ConcurrentProcessor {
    processor := &ConcurrentProcessor{
        shards:     make([]*ShardProcessor, shardCount),
        shardCount: shardCount,
    }

    for i := 0; i < shardCount; i++ {
        processor.shards[i] = &ShardProcessor{
            queue:  make(chan Event, queueSize),
            worker: worker,
            done:   make(chan struct{}),
        }
        go processor.shards[i].process()
    }

    return processor
}

func (p *ConcurrentProcessor) getShardID(eventID string) int {
    hash := fnv.New32a()
    hash.Write([]byte(eventID))
    return int(hash.Sum32()) % p.shardCount
}

func (p *ConcurrentProcessor) Process(event Event) error {
    shardID := p.getShardID(event.ID)
    event.ShardID = shardID

    select {
    case p.shards[shardID].queue <- event:
        return nil
    default:
        return errors.New("shard queue full - backpressure applied")
    }
}

func (s *ShardProcessor) process() {
    for {
        select {
        case event := <-s.queue:
            s.worker(event)
        case <-s.done:
            return
        }
    }
}

func (p *ConcurrentProcessor) Close() {
    for _, shard := range p.shards {
        close(shard.done)
    }
}
```

