  public void enqueue(T item) throws InterruptedException {
    lock.lock();
    try {
      while (count == buf.length && !shutdown) notFull.await();
      if (shutdown) throw new InterruptedException();
      buf[tail] = item; tail = (tail+1) % buf.length; count++;
      notEmpty.signalAll();
    } finally { lock.unlock(); }
  }

  public T dequeue() throws InterruptedException {
    lock.lock();
    try {
      while (count == 0 && !shutdown) notEmpty.await();
      if (shutdown && count == 0) return null;
      @SuppressWarnings("unchecked") T item = (T) buf[head]; buf[head] = null; head = (head+1) % buf.length; count--;
      notFull.signalAll();
      return item;
    } finally { lock.unlock(); }
  }

  public void shutdown() {
    lock.lock(); try { shutdown = true; notFull.signalAll(); notEmpty.signalAll(); } finally { lock.unlock(); }
  }
}
```

