import java.util.concurrent.*;

class WorkItem { final int priority; final Runnable task; WorkItem(int p, Runnable t){priority=p;this.task=t;} void run(){task.run();} }

public class MultiPriorityScheduler {
  private final BlockingQueue<WorkItem>[] queues = new BlockingQueue[3];
  private volatile boolean running = true;

  @SuppressWarnings("unchecked")
  public MultiPriorityScheduler(int cap){
    for(int i=0;i<3;i++) queues[i] = new ArrayBlockingQueue<>(cap);
  }

  public boolean submit(WorkItem w, long timeout, TimeUnit unit) throws InterruptedException {
    return queues[w.priority].offer(w, timeout, unit);
  }

  public void start(int workerCount){
    for(int i=0;i<workerCount;i++){
      new Thread(() -> {
        while(running){
          WorkItem w=null;
          for(int p=0;p<3;p++){
            w = queues[p].poll(50, TimeUnit.MILLISECONDS);
            if (w != null){ w.run(); break; }
          }
        }
      }).start();
    }
  }

  public void stop(){ running = false; }
}
