type Task struct {
  UserID  string
  Payload string
}

func worker(ctx context.Context, id int, tasks <-chan Task, wg *sync.WaitGroup) {
  defer wg.Done()
  for {
    select {
    case t := <-tasks:
      // simulate processing
      _ = t
      time.Sleep(5 * time.Millisecond)
      fmt.Printf("worker %d processed %s\n", id, t.Payload)
    case <-ctx.Done():
      return
    }
  }
}

func main() {
  minW, maxW := 2, 6
  queueCap := 64
  queue := make(chan Task, queueCap)
  var wg sync.WaitGroup
  var cancels []context.CancelFunc

  // start min workers
  for i := 0; i < minW; i++ {
    ctx, cancel := context.WithCancel(context.Background())
    cancels = append(cancels, cancel)
    wg.Add(1)
    go worker(ctx, i, queue, &wg)
  }

  // scaler
  go func() {
    ticker := time.NewTicker(100 * time.Millisecond)
    defer ticker.Stop()
    for range ticker.C {
      l := len(queue)
      if l > 32 && len(cancels) < maxW {
        // scale up
        ctx, cancel := context.WithCancel(context.Background())
        cancels = append(cancels, cancel)
        w := len(cancels) - 1
        wg.Add(1)
        go worker(ctx, w, queue, &wg)
      } else if l < 8 && len(cancels) > minW {
        // scale down
        cancel := cancels[len(cancels)-1]
        cancels = cancels[:len(cancels)-1]
        cancel()
      }
    }
  }()

  // producer: enqueue tasks
  for i := 0; i < 1000; i++ {
    t := Task{UserID: fmt.Sprintf("user-%d", i%20), Payload: fmt.Sprintf("payload-%d", i)}
    queue <- t // blocks when full (backpressure)
  }

  // graceful shutdown
  time.Sleep(1 * time.Second)
  for _, c := range cancels {
    c()
  }
  close(queue)
  wg.Wait()
}
