package main

import (
  "context"
  "fmt"
  "sync"
  "time"
)

type Event struct{ Payload string }

type Bucket struct {
  mu     sync.Mutex
  tokens int
  cap    int
  refill int
}

func (b *Bucket) TryTake() bool {
  b.mu.Lock()
  defer b.mu.Unlock()
  if b.tokens > 0 {
    b.tokens--
    return true
  }
  return false
}

func (b *Bucket) Refund(n int) {
  b.mu.Lock()
  b.tokens += n
  if b.tokens > b.cap {
    b.tokens = b.cap
  }
  b.mu.Unlock()
}

func (b *Bucket) StartRefill(interval time.Duration) {
  go func() {
    ticker := time.NewTicker(interval)
    for range ticker.C {
      b.mu.Lock()
      if b.tokens < b.cap {
        b.tokens += b.refill
        if b.tokens > b.cap { b.tokens = b.cap }
      }
      b.mu.Unlock()
    }
  }()
}

type Tenant struct {
  id           string
  in           chan Event
  bucket       *Bucket
  inFlight     int
  maxInFlight  int
}

func main() {
  ctx, cancel := context.WithCancel(context.Background())
  defer cancel()

  tA := &Tenant{id: "A", in: make(chan Event, 32), bucket: &Bucket{tokens: 10, cap: 10, refill: 1}, maxInFlight: 3}
  tB := &Tenant{id: "B", in: make(chan Event, 32), bucket: &Bucket{tokens: 8, cap: 8, refill: 1}, maxInFlight: 2}
  tA.bucket.StartRefill(120 * time.Millisecond)
  tB.bucket.StartRefill(120 * time.Millisecond)

  tenants := []*Tenant{tA, tB}

  // Simple dispatcher
  go func() {
    for {
      select {
      case <-ctx.Done():
        return
      default:
      }
      for _, t := range tenants {
        if t.inFlight >= t.maxInFlight {
          continue
        }
        if t.bucket.TryTake() {
          select {
          case e := <-t.in:
            t.inFlight++
            go func(ev Event, tt *Tenant) {
              time.Sleep(50 * time.Millisecond)
              tt.inFlight--
              tt.bucket.Refund(1)
              fmt.Printf("Tenant %s processed %s\n", tt.id, ev.Payload)
            }(e, t)
          default:
            t.bucket.Refund(1)
          }
        }
      }
      time.Sleep(1 * time.Millisecond)
    }
  }()

  // Producers with backpressure
  go func() {
    for i := 0; i < 100; i++ {
      tA.in <- Event{Payload: fmt.Sprintf("A-%d", i)}
      time.Sleep(20 * time.Millisecond)
    }
  }()
  go func() {
    for i := 0; i < 60; i++ {
      tB.in <- Event{Payload: fmt.Sprintf("B-%d", i)}
      time.Sleep(30 * time.Millisecond)
    }
  }()

  // Run for a while then shutdown
  time.Sleep(5 * time.Second)
  cancel()
  time.Sleep(200 * time.Millisecond)
}
